var UserConnection = Get<UserConnection>("UserConnection");
string processedFile = Get<string>("ProcessedFile");
string type = Get<string>("Type");

if(type == "IMEI") {

	if(string.IsNullOrEmpty(processedFile)) {

		var scheduler = new IMEICancelUERP(UserConnection);
		var result = scheduler.Process();

		Set("Success", result.Success);
		Set("Message", result.Message);

	} else {
		var scheduler = new IMEICancelUERP(UserConnection, processedFile);

		try {
			scheduler.ProcessFile();
			Set("Success", true);
		} catch(Exception e) {
			string errorMessage = e.Message;
			var innerExp = e.InnerException;
			if(innerExp != null) {
				errorMessage += $" - {innerExp.Message}";
			}
			Set("Message", errorMessage);	
		}
	}
} else if(type == "SO") {

	if(string.IsNullOrEmpty(processedFile)) {

		var scheduler = new SOCancelUERP(UserConnection);
		var result = scheduler.Process();

		Set("Success", result.Success);
		Set("Message", result.Message);

	} else {

		var scheduler = new SOCancelUERP(UserConnection, processedFile);

		try {
			scheduler.ProcessFile();
			Set("Success", true);
		} catch(Exception e) {
			string errorMessage = e.Message;
			var innerExp = e.InnerException;
			if(innerExp != null) {
				errorMessage += $" - {innerExp.Message}";
			}
			Set("Message", errorMessage);	
		}

	}
}

return true;
